from flask import Flask, request, jsonify
import pickle
import os
from datetime import datetime, timedelta

app = Flask(__name__)

CACHE_DIR = 'cache'
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def cache_key(url):
    return url.replace('/', '_')

def load_cache(key):
    file_path = os.path.join(CACHE_DIR, key)
    if os.path.exists(file_path):
        with open(file_path, 'rb') as f:
            data = pickle.load(f)
            if 'timestamp' in data and datetime.now() < data['timestamp'] + timedelta(hours=1):
                return data['data']
    return None

def save_cache(key, data):
    file_path = os.path.join(CACHE_DIR, key)
    with open(file_path, 'wb') as f:
        pickle.dump({'data': data, 'timestamp': datetime.now()}, f)

@app.route('/api', methods=['GET'])
def api():
    url = request.args.get('url')
    cached_data = load_cache(cache_key(url))
    
    if cached_data is not None:
        return jsonify(cached_data)
    
    # Simulate expensive API call
    response_data = {
        'metadata': {'timestamp': datetime.now()},
        'data': {
            'items': [1, 2, 3],
            'details': {'name': 'example', 'value': 'test'}
        }
    }
    
    save_cache(cache_key(url), response_data)
    return jsonify(response_data)

if __name__ == '__main__':
    app.run(debug=True)